request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?step1Name ?edgeName ?step2Name WHERE {
  ?emailResults a bboExt:ChoreographyTask .
  ?emailResults bbo:name "Email Results of Academic Review" .

  ?edge1 a bbo:SequenceFlow .
  ?edge1 bbo:has_sourceRef ?emailResults .
  ?edge1 bbo:has_targetRef ?mid .
  OPTIONAL { ?edge1 bbo:name ?e1Name . }
  OPTIONAL { ?mid bbo:name ?midName . }

  OPTIONAL {
    ?edge2 a bbo:SequenceFlow .
    ?edge2 bbo:has_sourceRef ?mid .
    ?edge2 bbo:has_targetRef ?next .
    OPTIONAL { ?edge2 bbo:name ?e2Name . }
    OPTIONAL { ?next bbo:name ?nextName . }
  }

  BIND(COALESCE(?midName, STR(?mid)) AS ?step1Name)
  BIND(COALESCE(?e1Name, "") AS ?edgeName)
  BIND(COALESCE(?nextName, STR(?next)) AS ?step2Name)
}
LIMIT 25
